#!/usr/bin/env python3

import os
import sys
import shutil
import subprocess
from pathlib import Path


ROOT = Path(__file__).resolve().parent
DIST_DIR = ROOT / "dist"
PACKAGE_NAME = f"{ROOT.name}.zip"


def run(cmd, check=True):
    print("+", " ".join(cmd), flush=True)
    subprocess.run(cmd, check=check)


def install_dependencies():
    requirements = ROOT / "requirements.txt"
    if requirements.exists():
        run([sys.executable, "-m", "pip", "install", "--disable-pip-version-check", "--no-input", "-r", str(requirements)])
    else:
        print("requirements.txt not found, skipping dependency installation.", flush=True)


def run_tests():
    pytest_ini = ROOT / "pytest.ini"
    tests_dir = ROOT / "tests"
    if pytest_ini.exists() or tests_dir.exists():
        run([sys.executable, "-m", "pytest", "-q"])
    else:
        print("No tests detected, skipping test execution.", flush=True)


def should_exclude(path: Path):
    excluded_names = {
        ".git",
        ".github",
        ".gitlab",
        ".venv",
        "venv",
        "__pycache__",
        ".pytest_cache",
        ".mypy_cache",
        ".ruff_cache",
        ".tox",
        "dist",
        "build",
        ".DS_Store",
    }
    excluded_suffixes = {".pyc", ".pyo"}
    parts = set(path.parts)
    if parts & excluded_names:
        return True
    if path.name in excluded_names:
        return True
    if path.suffix in excluded_suffixes:
        return True
    return False


def package():
    DIST_DIR.mkdir(exist_ok=True)
    archive_base = DIST_DIR / ROOT.name
    archive_path = DIST_DIR / PACKAGE_NAME

    if archive_path.exists():
        archive_path.unlink()

    staging = DIST_DIR / "_staging"
    if staging.exists():
        shutil.rmtree(staging)
    staging.mkdir()

    for item in ROOT.rglob("*"):
        if item == staging or DIST_DIR in item.parents or item == DIST_DIR:
            continue
        rel = item.relative_to(ROOT)
        if should_exclude(rel):
            continue
        target = staging / rel
        if item.is_dir():
            target.mkdir(parents=True, exist_ok=True)
        elif item.is_file():
            target.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(item, target)

    shutil.make_archive(str(archive_base), "zip", root_dir=staging)
    shutil.rmtree(staging)
    print(f"Created deployment package: {archive_path}", flush=True)


def main():
    os.chdir(ROOT)
    install_dependencies()
    run_tests()
    package()


if __name__ == "__main__":
    main()